testcases.ir:
%struct = type { i32, [100 x i8] }

define i64 @test_struct(ptr %foo, i64 %i) {
  %gep1 = getelementptr inbounds %struct, ptr %foo, i64 0, i32 1, i64 %i
  %gep2 = getelementptr inbounds %struct, ptr %foo, i64 0, i32 0
  %cast1 = ptrtoint ptr %gep1 to i64
  %cast2 = ptrtoint ptr %gep2 to i64
  %sub = sub i64 %cast1, %cast2
  ret i64 %sub
}

testcases.expected_optimized_ir:
%struct = type { i32, [100 x i8] }

define i64 @test_struct(ptr %foo, i64 %i) {
  %off = add i64 %i, 4
  ret i64 %off
}

define i64 @test_swap(ptr %foo, i64 %i) {
  %sub = sub nsw i64 42, %i
  ret i64 %sub
}

define <4 x i64> @test_vec(ptr %base, <4 x i32> %idx) {
  %ext = zext <4 x i32> %idx to <4 x i64>
  %sub = sub <4 x i64> %ext, <i64 10, i64 10, i64 10, i64 10>
  ret <4 x i64> %sub
}

%arrty = type [100 x i8]
define i64 @test_bitcast(ptr %foo, i64 %i) {
  %sub = sub nsw i64 %i, 5
  ret i64 %sub
}

